import { useEffect, useState } from "react";
import Link from "next/link";

export default function ProdutorDashboard({ user }: { user: any }) {
  const [stats, setStats] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        const token = localStorage.getItem("token");
        const res = await fetch("http://localhost:5000/api/v1/dashboard/produtor", {
          headers: {
            "Authorization": `Bearer ${token}`
          }
        });
        const json = await res.json();
        if (json.success) {
          setStats(json.data);
        }
      } catch (error) {
        console.error("Erro ao carregar dashboard", error);
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
  }, []);

  if (loading) return <div className="p-10 text-center text-gray-500">A carregar dados financeiros...</div>;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
      {/* Cabeçalho */}
      <div className="md:flex md:items-center md:justify-between mb-8">
        <div className="flex-1 min-w-0">
          <h2 className="text-2xl font-bold leading-7 text-gray-900 sm:text-3xl sm:truncate">
            Painel do Produtor
          </h2>
          <p className="mt-1 text-sm text-gray-500">
            Bem-vindo de volta, {user.nome}.
          </p>
        </div>
        <div className="mt-4 flex md:mt-0 md:ml-4">
          <Link href="/produtor/nova-safra" className="ml-3 inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500">
            <svg className="-ml-1 mr-2 h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            Nova Safra
          </Link>
        </div>
      </div>

      {/* KPIs */}
      <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-4 mb-8">
        {[
          { label: "Saldo Disponível", value: stats?.kpis.saldo_disponivel, color: "bg-green-500", icon: "💰" },
          { label: "Em Custódia", value: stats?.kpis.em_custodia, color: "bg-blue-500", icon: "🔒" },
          { label: "A Liquidar", value: stats?.kpis.a_liquidar, color: "bg-yellow-500", icon: "⏳" },
          { label: "Receita Total", value: stats?.kpis.receita_total, color: "bg-gray-800", icon: "📈" }
        ].map((kpi) => (
          <div key={kpi.label} className="bg-white overflow-hidden shadow rounded-lg border-l-4 border-transparent hover:border-green-500 transition-all">
            <div className="p-5">
              <div className="flex items-center">
                <div className={`flex-shrink-0 rounded-md p-3 ${kpi.color} text-white`}>
                  <span className="text-xl">{kpi.icon}</span>
                </div>
                <div className="ml-5 w-0 flex-1">
                  <dt className="text-sm font-medium text-gray-500 truncate">{kpi.label}</dt>
                  <dd className="text-lg font-bold text-gray-900">
                    {new Intl.NumberFormat('pt-AO', { style: 'currency', currency: 'AOA' }).format(kpi.value || 0)}
                  </dd>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Tabela de Vendas Recentes */}
      <div className="bg-white shadow overflow-hidden sm:rounded-lg">
        <div className="px-6 py-5 border-b border-gray-200 flex justify-between items-center">
          <h3 className="text-lg leading-6 font-medium text-gray-900">Últimas Vendas</h3>
          <Link href="/produtor/vendas" className="text-green-600 hover:text-green-800 text-sm font-medium">Ver todas</Link>
        </div>

        {stats?.ultimas_vendas && stats.ultimas_vendas.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Produto</th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Comprador</th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Valor</th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Estado</th>
                  <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Data</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {stats.ultimas_vendas.map((venda: any) => (
                  <tr key={venda.id}>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{venda.produto}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{venda.comprador}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {new Intl.NumberFormat('pt-AO', { style: 'currency', currency: 'AOA' }).format(venda.valor)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-100 text-green-800">
                        {venda.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {new Date(venda.data).toLocaleDateString()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="p-12 text-center">
            <svg className="mx-auto h-12 w-12 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 13h6m-3-3v6m-9 1V7a2 2 0 012-2h6l2 2h6a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2z" />
            </svg>
            <h3 className="mt-2 text-sm font-medium text-gray-900">Nenhuma venda registada</h3>
            <p className="mt-1 text-sm text-gray-500">Comece por publicar uma nova safra no mercado.</p>
          </div>
        )}
      </div>
    </div>
  );
}